import json
import statistics
from collections import Counter

def calculateStatistics(scores_json):
    try:
        scores = json.loads(scores_json)
    except json.JSONDecodeError:
        raise ValueError("Invalid JSON format")

    if not isinstance(scores, list):
        raise ValueError("Invalid JSON format")

    numeric_scores = []
    non_numeric_values = []

    for score in scores:
        if isinstance(score, str):
            try:
                numeric_scores.append(float(score))
            except ValueError:
                non_numeric_values.append(score)
        elif isinstance(score, (int, float)):
            numeric_scores.append(score)
        else:
            raise ValueError("Invalid score format")

    if not numeric_scores:
        raise ValueError("No numeric scores found")

    mean = statistics.mean(numeric_scores)
    median = statistics.median(numeric_scores)
    mode = statistics.mode(numeric_scores)

    mode_count = Counter(numeric_scores).most_common(1)[0][1]
    if mode_count > len(numeric_scores) / 2:
        mode = None  # No unique mode found

    return {
        "mean": mean,
        "median": median,
        "mode": mode,
        "non_numeric_values": non_numeric_values
    }

# Example usage:
scores_json = '[["90", "85", "95", "78", "92", "88"], ["90", "85", "95", "78", "92", "88"]]'
print(calculateStatistics(scores_json))
