import java.util.*;

class Edge {
    int from;
    int to;
    int capacity;
    int flow;
    double cost;

    Edge(int from, int to, int capacity, int flow, double cost) {
        this.from = from;
        this.to = to;
        this.capacity = capacity;
        this.flow = flow;
        this.cost = cost;
    }
}

class Graph {
    Map<Integer, List<Edge>> graph;

    Graph(int numNodes) {
        graph = new HashMap<>();
        for (int i = 0; i < numNodes; i++) {
            graph.put(i, new ArrayList<>());
        }
    }

    void addEdge(int from, int to, int capacity, int flow, double cost) {
        graph.get(from).add(new Edge(from, to, capacity, flow, cost));
        graph.get(to).add(new Edge(to, from, 0, 0, -cost));
    }

    double minCostFlow(int source, int sink, int[] parent, int[] distance, double[] flow) {
        double minCost = 0;
        while (true) {
            distance[source] = 0;
            PriorityQueue<int[]> queue = new PriorityQueue<>((a, b) -> Double.compare(a[1], b[1]));
            queue.add(new int[]{source, 0});
            while (!queue.isEmpty()) {
                int[] current = queue.poll();
                int node = current[0];
                for (Edge edge : graph.get(node)) {
                    if (edge.capacity - edge.flow > 0 && distance[edge.to] > distance[node] + edge.cost) {
                        distance[edge.to] = distance[node] + edge.cost;
                        parent[edge.to] = node;
                        queue.add(new int[]{edge.to, distance[edge.to]});
                    }
                }
            }
            boolean updated = false;
            for (int node = source; node != sink; node = parent[node]) {
                for (Edge edge : graph.get(node)) {
                    if (edge.flow < edge.capacity && distance[node] + edge.cost == distance[edge.to]) {
                        flow[edge.to]++;
                        flow[edge.from]--;
                        updated = true;
                    }
                }
            }
            if (!updated) break;
            minCost += distance[sink] * flow[sink];
        }
        return minCost;
    }
}

public class Main {
    public static void trafficOptimizer(int[][] graph, int source, int sink) {
        int numNodes = graph.length;
        Graph g = new Graph(numNodes);
        for (int i = 0; i < numNodes; i++) {
            for (int[] edge : graph[i]) {
                g.addEdge(i, edge[0], edge[1], 0, 0);
            }
        }
        int[] distance = new int[numNodes];
        int[] parent = new int[numNodes];
        double[] flow = new double[numNodes];
        System.out.println(g.minCostFlow(source, sink, parent, distance, flow));
    }

    public static void main(String[] args) {
        int[][] graph = {{0, 16, 13, 0, 0, 0},
                {0, 0, 10, 12, 0, 0},
                {0, 4, 0, 0, 14, 0},
                {0, 0, 9, 0, 0, 20},
                {0, 0, 0, 7, 0, 4},
                {0, 0, 0, 0, 0, 0}};
        trafficOptimizer(graph, 0, 5);
    }
}
