struct ReqStruct {
    int requestID;
    std::string endpoint;
    std::string payload;
};

std::unordered_map<std::string, int> validateEndpoint(const std::string& endpoint) {
    std::unordered_map<std::string, int> endpointRules = {
        {"login", 1},
        {"logout", 2},
        {"get_user", 3},
        {"create_user", 4}
    };

    auto it = endpointRules.find(endpoint);
    return it != endpointRules.end() ? {endpoint, it->second} : {endpoint, -1};
}

std::string processNetworkRequests(const ReqStruct& request) {
    if (request.endpoint.empty()) {
        throw std::invalid_argument("Endpoint cannot be empty");
    }

    auto validatedEndpoint = validateEndpoint(request.endpoint);
    if (validatedEndpoint.second == -1) {
        return "Error: Invalid endpoint";
    }

    std::string response;
    if (validatedEndpoint.first == "login") {
        // Generate login response
        response = "Login successful";
    } else if (validatedEndpoint.first == "logout") {
        // Generate logout response
        response = "Logout successful";
    } else if (validatedEndpoint.first == "get_user") {
        // Generate get user response
        response = "User details retrieved successfully";
    } else if (validatedEndpoint.first == "create_user") {
        // Generate create user response
        response = "User created successfully";
    }

    return response;
}

