std::set<std::string> filterUniqueErrors(const std::set<std::string>& errorCodes) {
    std::unordered_map<std::string, std::string> errorCategories = {
        {"EC01", "Critical"},
        {"EC02", "Warning"},
        {"EC03", "Info"},
        {"EC04", "Critical"},
        {"EC05", "Warning"},
        {"EC06", "Info"}
    };

    std::set<std::string> uniqueErrors;
    std::set<std::string> classifiedErrors;

    for (const auto& errorCode : errorCodes) {
        if (errorCategories.find(errorCode) != errorCategories.end()) {
            classifiedErrors.insert(errorCode + ": " + errorCategories[errorCode]);
        }
    }

    for (const auto& error : classifiedErrors) {
        uniqueErrors.insert(error);
    }

    return uniqueErrors;
}

int main() {
    std::set<std::string> errorCodes = {"EC01", "EC02", "EC03", "EC04", "EC05", "EC06", "EC01", "EC02"};
    std::set<std::string> uniqueErrors = filterUniqueErrors(errorCodes);

    for (const auto& error : uniqueErrors) {
        std::cout << error << std::endl;
    }

    return 0;
}
