import java.util.*;

public class NetworkAnalyzer {
    public static List<String> analyzeNetworkConnectivity(Map<String, List<String>> graph) {
        int totalNodes = graph.size();
        List<String> criticalNodes = new ArrayList<>();

        for (Map.Entry<String, List<String>> entry : graph.entrySet()) {
            String node = entry.getKey();
            List<String> neighbors = entry.getValue();

            if (neighbors.size() == (totalNodes - 1)) {
                criticalNodes.add(node);
            }
        }

        return criticalNodes;
    }

    public static void main(String[] args) {
        Map<String, List<String>> graph = new HashMap<>();
        graph.put("A", Arrays.asList("B", "C"));
        graph.put("B", Arrays.asList("A", "D", "E"));
        graph.put("C", Arrays.asList("A", "F"));
        graph.put("D", Arrays.asList("B"));
        graph.put("E", Arrays.asList("B", "F"));
        graph.put("F", Arrays.asList("C", "E"));

        List<String> criticalNodes = analyzeNetworkConnectivity(graph);
        System.out.println(criticalNodes);
