#include <iostream>
#include <fstream>
#include <string>
#include <stdexcept>
#include <sstream>

void processCommandLine(const std::string& configFilePath, const std::string& command) {
    std::ifstream configFile(configFilePath);
    if (!configFile.is_open()) {
        std::cerr << "Failed to open configuration file." << std::endl;
        return;
    }

    std::string line, setting;
    bool settingFound = false;

    while (std::getline(configFile, line)) {
        if (line[0] != '#') {
            size_t equalsPos = line.find('=');
            if (equalsPos != std::string::npos) {
                setting = line.substr(0, equalsPos);
                settingFound = true;
                if (command == "set") {
                    std::string value;
                    std::getline(configFile, value);
                    configFile.seekg(0, std::ios::beg);
                    std::stringstream ss;
                    ss << setting << "=" << value;
                    configFile << ss.str();
                    configFile.seekg(0, std::ios::end);
                    configFile.seekg(0, std::ios::beg);
                    configFile << "\n";
                } else if (command == "display") {
                    if (settingFound) {
                        std::cout << setting << "=" << std::string(line.substr(equalsPos + 1)) << std::endl;
                    } else {
                        std::cout << "No setting found." << std::endl;
                    }
                } else if (command == "reset") {
                    configFile.seekg(0, std::ios::beg);
                    std::string lineTemp;
                    while (std::getline(configFile, lineTemp)) {
                        if (lineTemp[0] != '#') {
                            configFile << "\n";
                        }
                    }
                    configFile.close();
                    processCommandLine(configFilePath, "set");
                } else {
                    std::cerr << "Invalid command." << std::endl;
                }
            }
        }
    }

    configFile.close();
}

int main(int argc, char* argv[]) {
    if (argc != 3) {
        std::cerr << "Usage: " << argv[0] << " <config_file_path> <command>" << std::endl;
        return 1;
    }

    processCommandLine(argv[1], argv[2]);

    return 0;
}
