use std::collections::HashMap;

enum ActionType {
    Allocate,
    Deallocate,
    Status,
}

struct GateAction {
    gate_id: String,
    action_type: ActionType,
}

struct AirportGates {
    gates: HashMap<String, GateAction>,
}

impl AirportGates {
    fn new() -> Self {
        Self {
            gates: HashMap::new(),
        }
    }

    fn manageAirportGates(&mut self, action: GateAction) {
        match action.action_type {
            ActionType::Allocate => self.allocate_gate(&action),
            ActionType::Deallocate => self.deallocate_gate(&action),
            ActionType::Status => self.check_gate_status(&action),
        }
    }

    fn allocate_gate(&mut self, gate_action: &GateAction) {
        if self.gates.contains_key(&gate_action.gate_id) {
            panic!("Gate already allocated");
        }
        self.gates.insert(gate_action.gate_id.clone(), gate_action.clone());
    }

    fn deallocate_gate(&mut self, gate_action: &GateAction) {
        if !self.gates.contains_key(&gate_action.gate_id) {
            panic!("Gate not allocated");
        }
        self.gates.remove(&gate_action.gate_id);
    }

    fn check_gate_status(&self, gate_action: &GateAction) {
        if self.gates.contains_key(&gate_action.gate_id) {
            println!("Gate {} is allocated", gate_action.gate_id);
        } else {
            println!("Gate {} is not allocated", gate_action.gate_id);
        }
    }
}

fn main() {
    let mut airport_gates = AirportGates::new();
    let gate_action1 = GateAction {
        gate_id: "gate1".to_string(),
        action_type: ActionType::Allocate,
    };
    let gate_action2 = GateAction {
        gate_id: "gate2".to_string(),
        action_type: ActionType::Allocate,
    };
    let gate_action3 = GateAction {
        gate_id: "gate1".to_string(),
        action_type: ActionType::Deallocate,
    };

    airport_gates.manageAirportGates(gate_action1);
    airport_gates.manageAirportGates(gate_action2);
    airport_gates.manageAirportGates(gate_action3);
    airport_gates.manageAirportGates(GateAction {
        gate_id: "gate1".to_string(),
        action_type: ActionType::Status,
    });
}
