    map<string, pair<string, string>> manageAirportGates(map<string, string> actions) {
        map<string, string> gates;

        for (auto& action : actions) {
            if (action["action"] == "assign") {
                string flight = action["flight"];
                string gate = action["gate"];
                if (gates.find(gate) == gates.end()) {
                    gates[gate] = flight;
                } else {
                    cout << "Gate " << gate << " is already assigned to another flight." << endl;
                }
            } else if (action["action"] == "unassign") {
                string gate = action["gate"];
                if (gates.find(gate) != gates.end()) {
                    gates.erase(gate);
                } else {
                    cout << "Gate " << gate << " is not assigned to any flight." << endl;
                }
            } else if (action["action"] == "query") {
                string gate = action["gate"];
                if (gates.find(gate) != gates.end()) {
                    cout << "Flight " << gates[gate] << " is assigned to gate " << gate << "." << endl;
                } else {
                    cout << "Gate " << gate << " is not assigned to any flight." << endl;
                }
            }
        }

        return gates;
    }
};

