import java.time.LocalDateTime;
import java.util.*;

public class LoginHistoryManager {
    private static Map<String, List<Map<String, Object>>> loginHistory = new HashMap<>();

    public static void processLoginHistory(Map<String, Object> operation) {
        if (operation.get("type").equals("add")) {
            addLogin(operation);
        } else if (operation.get("type").equals("retrieve")) {
            retrieveLogin(operation);
        } else if (operation.get("type").equals("delete")) {
            deleteLogin(operation);
        }
    }

    private static void addLogin(Map<String, Object> operation) {
        String userId = (String) operation.get("user_id");
        String timestamp = (String) operation.get("timestamp");
        if (!loginHistory.containsKey(userId)) {
            loginHistory.put(userId, new ArrayList<>());
        }
        loginHistory.get(userId).add(new HashMap<String, Object>() {{
            put("timestamp", timestamp);
        }});
    }

    private static void retrieveLogin(Map<String, Object> operation) {
        String userId = (String) operation.get("user_id");
        if (loginHistory.containsKey(userId)) {
            List<Map<String, Object>> recentLogins = loginHistory.get(userId);
            Collections.sort(recentLogins, Comparator.comparing(Map::get, Map::get("timestamp")).reversed());
            List<Map<String, Object>> recentLoginsRetrieved = recentLogins.subList(0, Math.min(10, recentLogins.size()));
            System.out.println(recentLoginsRetrieved);
        } else {
            System.out.println("User ID not found");
        }
    }

    private static void deleteLogin(Map<String, Object> operation) {
        String userId = (String) operation.get("user_id");
        String timestamp = (String) operation.get("timestamp");
        if (loginHistory.containsKey(userId)) {
            loginHistory.get(userId).removeIf(login -> login.get("timestamp").equals(timestamp));
            if (loginHistory.get(userId).isEmpty()) {
                loginHistory.remove(userId);
            }
        } else {
            System.out.println("User ID not found");
        }
    }

    public static void main(String[] args) {
        Map<String, Object> addOperation = new HashMap<>();
        addOperation.put("type", "add");
        addOperation.put("user_id", "user1");
        addOperation.put("timestamp", LocalDateTime.now().toString());
        processLoginHistory(addOperation);

        Map<String, Object> retrieveOperation = new HashMap<>();
        retrieveOperation.put("type", "retrieve");
        retrieveOperation.put("user_id", "user1");
        processLoginHistory(retrieveOperation);

        Map<String, Object> deleteOperation = new HashMap<>();
        deleteOperation.put("type", "delete");
        deleteOperation.put("user_id", "user1");
        deleteOperation.put("timestamp", LocalDateTime.now().toString());
        processLoginHistory(deleteOperation);
    }
}
