def manageStudentRecords(student_data):
    """
    This function handles operations on student data such as adding, updating, and removing student details, 
    along with fetching specific student information.

    Args:
        student_data (list): A list of dictionaries where each dictionary represents a student.
            Each dictionary should contain the following keys:
                - operation (str): The operation to be performed. Can be 'add', 'update', 'remove', or 'fetch'.
                - student_id (int): The ID of the student.
                - name (str): The name of the student.
                - age (int): The age of the student.

    Returns:
        list: The updated list of student data.
    """

    # Create a dictionary to store student data
    student_dict = {}

    # Iterate over each student in the input list
    for student in student_data:
        # Check the operation
        if student['operation'] == 'add':
            # Add the student to the dictionary
            student_dict[student['student_id']] = {
                'name': student['name'],
                'age': student['age']
            }
        elif student['operation'] == 'update':
            # Update the student in the dictionary
            if student['student_id'] in student_dict:
                student_dict[student['student_id']]['name'] = student['name']
                student_dict[student['student_id']]['age'] = student['age']
        elif student['operation'] == 'remove':
            # Remove the student from the dictionary
            if student['student_id'] in student_dict:
                del student_dict[student['student_id']]
        elif student['operation'] == 'fetch':
            # Fetch the student's information
            if student['student_id'] in student_dict:
                return [student_dict[student['student_id']]]
            else:
                return []
        else:
            # Raise an error for invalid operations
            raise ValueError("Invalid operation")

    # Return the updated list of student data
    return list(student_dict.values())

# Example usage
student_data = [
    {'operation': 'add', 'student_id': 1, 'name': 'John Doe', 'age': 20},
    {'operation': 'add', 'student_id': 2, 'name': 'Jane Doe', 'age': 22},
    {'operation': 'update', 'student_id': 1, 'name': 'John Smith', 'age': 21},
    {'operation': 'fetch', 'student_id': 2},
    {'operation': 'remove', 'student_id': 1}
]

print(manageStudentRecords(student_data))
