                        reminderDetails.put("date", date);
                        reminderDetails.put("time", time);
                        reminderDetails.put("importance", importance);
                        reminders.put(eventType, reminderDetails);
                    } else {
                        Map<String, Object> reminderDetails = new HashMap<>();
                        reminderDetails.put("date", date);
                        reminderDetails.put("time", time);
                        reminders.put(eventType, reminderDetails);
                    }
                }
            }

            if (inputData.has("set_reminder_time")) {
