    return newNode;
}

// Function to add a child to a node
void addChild(Node* parent, string childName) {
    if (parent->children.find(childName) != parent->children.end()) {
        cout << "Child node already exists." << endl;
        return;
    }
    parent->children[childName] = nullptr;
}

// Function to update a node
void updateNode(Node* node, string oldName, string newName) {
    if (node->name == oldName) {
        node->name = newName;
        return;
    }
    for (auto& child : node->children) {
        updateNode(child.second, oldName, newName);
    }
}

// Function to remove a child from a node
void removeChild(Node* parent, string childName) {
    if (parent->children.find(childName) == parent->children.end()) {
        cout << "Child node does not exist." << endl;
        return;
    }
    parent->children.erase(childName);
}

// Function to manage permissions
void managePermissions(Node* root, string operation, string* details) {
    if (operation == "add") {
        if (details[0] == "child") {
            addChild(root, details[1]);
        } else if (details[0] == "parent") {
            string parentName = details[1];
            for (auto& child : root->children) {
                if (child.second != nullptr && child.second->name == parentName) {
                    addChild(child.second, details[1]);
                    return;
                }
