        } else if (details[0] == "parent") {
            string parentName = details[1];
            for (auto& child : root->children) {
                if (child.second != nullptr && child.second->name == parentName) {
                    updateNode(child.second, details[2], details[3]);
                    return;
                }
            }
            cout << "Parent node does not exist." << endl;
        } else {
            cout << "Invalid operation." << endl;
        }
    } else if (operation == "remove") {
        if (details[0] == "child") {
            removeChild(root, details[1]);
        } else if (details[0] == "parent") {
            string parentName = details[1];
            for (auto& child : root->children) {
                if (child.second != nullptr && child.second->name == parentName) {
                    removeChild(child.second, details[1]);
