import java.util.regex.Matcher;

public class Main {
    public static String processPaymentInfo(String paymentJson) {
        try {
            // Parse JSON
            JSONObject paymentDetails = new JSONObject(paymentJson);

            // Validate card type
            if (!paymentDetails.getString("cardType").matches("^\\d+$")) {
                return "{\"isValid\": false, \"transactionStatus\": \"Invalid card type\"}";
            }

            // Validate card number
            String cardNumber = paymentDetails.getString("cardNumber");
            if (!Pattern.matches("\\d+", cardNumber) || cardNumber.length() < 13 || cardNumber.length() > 16) {
                return "{\"isValid\": false, \"transactionStatus\": \"Invalid card number\"}";
            }

            // Apply Luhn's algorithm
            int sum = 0;
            boolean alternate = false;
            for (int i = cardNumber.length() - 1; i >= 0; i--) {
                int digit = Character.getNumericValue(cardNumber.charAt(i));
                if (alternate) {
                    digit *= 2;
                    if (digit > 9) {
                        digit -= 9;
                    }
                }
                sum += digit;
                alternate = !alternate;
            }

            // Check if sum is divisible by 10
            if (sum % 10 != 0) {
                return "{\"isValid\": false, \"transactionStatus\": \"Invalid card number\"}";
            }

            // If all checks pass, payment is valid
            return "{\"isValid\": true, \"transactionStatus\": \"Payment successful\"}";
        } catch (Exception e) {
            return "{\"isValid\": false, \"transactionStatus\": \"Invalid JSON\"}";
        }
    }

    public static void main(String[] args) {
        String paymentJson = "{\"cardType\": \"1234567890123456\", \"cardNumber\": \"4532118530130435\", \"amount\": 100.50}";
        System.out.println(processPaymentInfo(paymentJson));
    }
}
