// Define an enum for action types
enum ActionType {
    AddNode,
    UpdateNode,
    RemoveNode,
    GetConfig,
}

// Define a struct for network node
struct Node {
    id: String,
    config: HashMap<String, String>,
}

// Define a struct for the tree
struct Tree {
    root: Option<Node>,
    nodes: HashMap<String, Node>,
}

impl Tree {
    // Create a new tree
    fn new() -> Tree {
        Tree {
            root: None,
            nodes: HashMap::new(),
        }
    }

    // Add a new node to the tree
    fn add_node(&mut self, id: String, config: HashMap<String, String>) {
        self.nodes.insert(id, Node { id, config });
        if self.root.is_none() {
            self.root = Some(self.nodes.get(&id).unwrap().clone());
        }
    }

    // Update a node's configuration in the tree
    fn update_node(&mut self, id: String, config: HashMap<String, String>) {
        if let Some(node) = self.nodes.get_mut(&id) {
            node.config = config;
        }
    }

    // Remove a node from the tree
    fn remove_node(&mut self, id: String) {
        if let Some(node) = self.nodes.remove(&id) {
            if self.root == Some(node) {
                self.root = None;
            }
        }
    }

    // Get the configuration of a node in the tree
    fn get_config(&self, id: &str) -> Option<&HashMap<String, String>> {
        self.nodes.get(id).map(|node| &node.config)
    }
}

// Define the manageNetworkConfig function
fn manageNetworkConfig(tree: &mut Tree, action_type: ActionType, id: String, config: Option<HashMap<String, String>>) {
    match action_type {
        ActionType::AddNode => tree.add_node(id, config.unwrap()),
        ActionType::UpdateNode => tree.update_node(id, config.unwrap()),
        ActionType::RemoveNode => tree.remove_node(id),
        ActionType::GetConfig => {
            if let Some(config) = tree.get_config(&id) {
                println!("{:?}", config);
            } else {
                println!("Node not found.");
            }
        }
    }
}
