import org.json.JSONObject;

import java.util.*;

public class GraphTraversalManager {
    public static Object graphTraversalManager(Object graphInput) {
        JSONObject graphData = (JSONObject) graphInput;
        String algorithm = graphData.getString("algorithm");
        String startNode = graphData.getString("startNode");
        boolean isDirected = graphData.getBoolean("isDirected");

        Map<String, Object> graph = new HashMap<>();
        graph.put("adjacencyList", graphData.getJSONObject("adjacencyList"));
        graph.put("edges", graphData.getJSONObject("edges"));

        Map<String, Object> result = new HashMap<>();

        if (algorithm.equals("BFS")) {
            result.put("traversalOrder", bfs(graph, startNode, isDirected));
        } else if (algorithm.equals("DFS")) {
            result.put("traversalOrder", dfs(graph, startNode, isDirected));
        } else {
            result.put("error", "Invalid algorithm");
        }

        return result;
    }

    private static List<String> bfs(Map<String, Object> graph, String startNode, boolean isDirected) {
        Map<String, Boolean> visited = new HashMap<>();
        Queue<String> queue = new LinkedList<>();
        queue.add(startNode);
        visited.put(startNode, true);

        List<String> traversalOrder = new ArrayList<>();

        while (!queue.isEmpty()) {
            String currentNode = queue.poll();
            traversalOrder.add(currentNode);

            if (isDirected) {
                for (Map.Entry<String, Object> entry : ((Map<String, List<String>>) graph.get("adjacencyList")).get(currentNode).asList()) {
                    if (!visited.containsKey(entry.getKey())) {
                        queue.add(entry.getKey());
                        visited.put(entry.getKey(), true);
                    }
                }
            } else {
                for (String neighbor : ((List<String>) graph.get("adjacencyList")).get(currentNode)) {
                    if (!visited.containsKey(neighbor)) {
                        queue.add(neighbor);
                        visited.put(neighbor, true);
                    }
                }
            }
        }

        return traversalOrder;
    }

    private static List<String> dfs(Map<String, Object> graph, String startNode, boolean isDirected) {
        Map<String, Boolean> visited = new HashMap<>();
        Stack<String> stack = new Stack<>();
        stack.push(startNode);
        visited.put(startNode, true);

        List<String> traversalOrder = new ArrayList<>();

        while (!stack.isEmpty()) {
            String currentNode = stack.pop();
            traversalOrder.add(currentNode);

            if (isDirected) {
                for (Map.Entry<String, Object> entry : ((Map<String, List<String>>) graph.get("adjacencyList")).get(currentNode).asList()) {
                    if (!visited.containsKey(entry.getKey())) {
                        stack.push(entry.getKey());
                        visited.put(entry.getKey(), true);
                    }
                }
            } else {
                for (String neighbor : ((List<String>) graph.get("adjacencyList")).get(currentNode)) {
                    if (!visited.containsKey(neighbor)) {
                        stack.push(neighbor);
                        visited.put(neighbor, true);
                    }
                }
            }
        }

        return traversalOrder;
    }

    public static void main(String[] args) {
        JSONObject graphInput = new JSONObject()
                .put("algorithm", "BFS")
                .put("startNode", "A")
                .put("adjacencyList", new JSONObject()
                        .put("A", Arrays.asList("B", "C"))
                        .put("B", Arrays.asList("A", "D"))
                        .put("C", Arrays.asList("A", "D"))
                        .put("D", Arrays.asList("B", "C"))
                )
                .put("edges", new JSONObject());
        System.out.println(graphTraversalManager(graphInput));
    }
}
