    fn new() -> Self {
        TaskManager {
            tasks: vec![],
        }
    }

    fn manage_task_priority(&mut self, request: Value) {
        if let Some(task_id) = request.get("task_id").and_then(|v| v.as_u64()) {
            if let Some(new_priority) = request.get("new_priority").and_then(|v| v.as_u64()) {
                self.tasks.iter_mut()
                    .filter(|(task_id, _)| **task_id == *task_id)
                    .for_each(|(_, priority)| {
                        if *priority != new_priority {
                            *priority = new_priority;
                        }
                    });
            } else {
                println!("Error: 'new_priority' key is missing in the request.");
            }
        } else {
            println!("Error: 'task_id' key is missing in the request.");
        }
    }

    fn get_task_priority(&self, task_id: i32) -> Option<i32> {
        self.tasks.iter().find(|(id, _)| **id == task_id).map(|(_, priority)| **priority)
    }
}

fn main() {
    let mut task_manager = TaskManager::new();

    let request = Value::Object(vec![
        ("task_id".to_string(), 1),
        ("new_priority".to_string(), 3),
    ]);

