import java.util.*;

public class FileSystemSimulator {
    private static Map<String, Object> root;

    public static void main(String[] args) {
        root = new HashMap<>();
        root = fs_simulator(root, new String[]{"add", "folder", "docs"});
        root = fs_simulator(root, new String[]{"add", "folder", "pics"});
        root = fs_simulator(root, new String[]{"add", "file", "readme.txt", "docs"});
        root = fs_simulator(root, new String[]{"add", "file", "image.jpg", "pics"});
        root = fs_simulator(root, new String[]{"move", "file", "readme.txt", "pics"});
        root = fs_simulator(root, new String[]{"fetch", "path", "pics"});
    }

    public static Map<String, Object> fs_simulator(Map<String, Object> current, String[] action) {
        String actionType = action[0];
        String folderName = (String) action[1];

        if (actionType.equals("add")) {
            if (folderName.contains(".")) {
                current.put(folderName, new HashMap<>());
            } else {
                current.put(folderName, null);
            }
        } else if (actionType.equals("move")) {
            if (current.containsKey(folderName)) {
                current.put(folderName, null);
            }
        } else if (actionType.equals("remove")) {
            if (current.containsKey(folderName)) {
                current.remove(folderName);
            }
        } else if (actionType.equals("fetch")) {
            return folderPath(current, folderName);
        }

        return current;
    }

    public static Map<String, Object> folderPath(Map<String, Object> current, String folderName) {
        Map<String, Object> path = new HashMap<>();
        path.put("folder", folderName);

        if (current.containsKey(folderName)) {
            return path;
        } else {
            List<String> subFolders = new ArrayList<>();
            for (Map.Entry<String, Object> entry : current.entrySet()) {
                if (entry.getValue() instanceof Map) {
                    subFolders.add(entry.getKey());
                    Map<String, Object> subPath = folderPath((Map<String, Object>) entry.getValue(), folderName);
                    if (subPath != null) {
                        subPath.put("folder", entry.getKey());
                        subFolders.add(subPath.toString());
                    }
                }
            }
            if (!subFolders.isEmpty()) {
                path.put("subfolders", subFolders);
            }
            return path;
        }
    }
}
