public class OrderProcessor {
    public static List<Map<String, Double>> processOrderList(List<Map<String, Double>> orderList, double threshold) {
        return orderList.stream()
                .filter(order -> order.get("orderAmount") >= threshold)
                .collect(Collectors.toList());
