fn calculate_divisors(n: i32) -> Vec<i32> {
    if n <= 0 {
        return Vec::new();
    }

    let mut divisors = Vec::new();

    for i in 1..=n {
        if n % i == 0 {
            divisors.push(i);
        }
    }

    divisors.sort();
    divisors
}

fn main() {
    println!("{:?}", calculate_divisors(10));
    println!("{:?}", calculate_divisors(-5));
}
