class ConfigTree:
    def __init__(self, config):
        self.config = config
        self.children = {}

    def add_child(self, key, value):
        if key not in self.config:
            self.children[key] = ConfigTree(value)
        else:
            self.config[key] = ConfigTree(value)

    def modify(self, key, value):
        if key in self.config:
            self.config[key] = value
        elif key in self.children:
            self.children[key].config = value

    def get_config(self, key, default=None):
        if key in self.config:
            return self.config[key].config
        elif key in self.children:
            return self.children[key].get_config(key, default)
        else:
            return default


def generateConfigTree(config):
    root = ConfigTree(config)
    return root


# Example usage:
config = {
    "hostname": "Device1",
    "ip_addresses": {
        "interface": "eth0",
