#include <iostream>
#include <queue>
#include <vector>
#include <limits>

using namespace std;

struct Node {
    int node;
    int distance;
    vector<int> path;
};

struct CompareNodes {
    bool operator()(const Node& a, const Node& b) {
        return a.distance > b.distance;
    }
};

vector<int> findShortestPath(vector<vector<int>>& graph, int start, int end) {
    int numNodes = graph.size();
    vector<bool> visited(numNodes, false);
    vector<Node> nodes(numNodes);

    for (int i = 0; i < numNodes; i++) {
        nodes[i].node = i;
        nodes[i].distance = (i == start) ? 0 : numeric_limits<int>::max();
        nodes[i].path = {};
    }

    priority_queue<Node, vector<Node>, CompareNodes> priorityQueue;
    priorityQueue.push({start, 0, {start}});

    while (!priorityQueue.empty()) {
        Node currentNode = priorityQueue.top();
        priorityQueue.pop();

        if (visited[currentNode.node]) {
            continue;
        }

        visited[currentNode.node] = true;

        for (int neighbor : graph[currentNode.node]) {
            if (visited[neighbor]) {
                continue;
            }

            int distance = currentNode.distance + 1;
            vector<int> newPath = currentNode.path;
            newPath.push_back(neighbor);

            if (distance < nodes[neighbor].distance) {
                nodes[neighbor].distance = distance;
                nodes[neighbor].path = newPath;
                priorityQueue.push({neighbor, distance, newPath});
            }
        }
    }

    return nodes[end].path;
}
