import java.util.Map;

class TreeNode {
    String name;
    Map<String, Object> properties;
    TreeNode[] children;

    public TreeNode(String name, Map<String, Object> properties) {
        this.name = name;
        this.properties = properties;
        this.children = new TreeNode[0];
    }

    public void addChild(TreeNode child) {
        TreeNode[] newChildren = new TreeNode[children.length + 1];
        System.arraycopy(children, 0, newChildren, 0, children.length);
        newChildren[children.length] = child;
        children = newChildren;
    }
}

public class ApplicationSettings {
    public static void configureApplicationSettings(TreeNode tree) {
        if (tree.properties != null) {
            for (Map.Entry<String, Object> entry : tree.properties.entrySet()) {
                String key = entry.getKey();
                Object value = entry.getValue();

                if (value instanceof String) {
                    System.out.println("Setting '" + key + "' to '" + value + "'");
                } else if (value instanceof Map) {
                    TreeNode child = (TreeNode) value;
                    tree.addChild(child);
                }
            }
        }

        for (TreeNode child : tree.children) {
            configureApplicationSettings(child);
        }
    }

    public static void main(String[] args) {
        TreeNode root = new TreeNode("Root", Map.of(
                "database", Map.of("host", "localhost", "port", 5432),
                "logging", Map.of("level", "INFO")
        ));

        TreeNode child = new TreeNode("Child", Map.of(
                "database", Map.of("username", "user"),
                "logging", Map.of("format", "JSON")
        ));
        root.addChild(child);

        configureApplicationSettings(root);
    }
}
