#include <stdexcept>

int calculateFactorial(int n) {
    if (n < 0) {
        throw std::invalid_argument("Factorial is not defined for negative numbers");
    }
    else if (n == 0 || n == 1) {
        return 1;
    }
    else {
        int result = 1;
        for (int i = 2; i <= n; i++) {
            result *= i;
        }
        return result;
    }
}
