import java.util.Arrays;

public class Main {
    public static int[][] transformMatrix(int[][] matrix, String operationMode) {
        if (operationMode.equals("rotate_left")) {
            return rotateLeft(matrix);
        } else if (operationMode.equals("rotate_right")) {
            return rotateRight(matrix);
        } else if (operationMode.equals("flip_vertical")) {
            return flipVertical(matrix);
        } else if (operationMode.equals("flip_horizontal")) {
            return flipHorizontal(matrix);
        } else {
            throw new IllegalArgumentException("Invalid operation mode");
        }
    }

    public static int[][] rotateLeft(int[][] matrix) {
        int[][] rotatedMatrix = new int[matrix[0].length][matrix.length];
        for (int i = 0; i < matrix.length; i++) {
            for (int j = 0; j < matrix[0].length; j++) {
                rotatedMatrix[j][matrix.length - i - 1] = matrix[i][j];
            }
        }
        return rotatedMatrix;
    }

    public static int[][] rotateRight(int[][] matrix) {
        int[][] rotatedMatrix = new int[matrix[0].length][matrix.length];
        for (int i = 0; i < matrix.length; i++) {
            for (int j = 0; j < matrix[0].length; j++) {
                rotatedMatrix[j][i] = matrix[matrix.length - i - 1][j];
            }
        }
        return rotatedMatrix;
    }

    public static int[][] flipVertical(int[][] matrix) {
        int[][] flippedMatrix = new int[matrix[0].length][matrix.length];
        for (int i = 0; i < matrix.length; i++) {
            for (int j = 0; j < matrix[0].length; j++) {
                flippedMatrix[j][matrix.length - i - 1] = matrix[i][j];
            }
        }
        return flippedMatrix;
    }

    public static int[][] flipHorizontal(int[][] matrix) {
        int[][] flippedMatrix = new int[matrix[0].length][matrix.length];
        for (int i = 0; i < matrix.length; i++) {
            for (int j = 0; j < matrix[0].length; j++) {
                flippedMatrix[i][j] = matrix[matrix.length - i - 1][j];
            }
        }
        return flippedMatrix;
    }

    public static void main(String[] args) {
        int[][] matrix = {{1, 2, 3}, {4, 5, 6}, {7, 8, 9}};
        int[][] transformedMatrix = transformMatrix(matrix, "rotate_left");
        for (int i = 0; i < transformedMatrix.length; i++) {
            System.out.println(Arrays.toString(transformedMatrix[i]));
        }
    }
}
